TriggerOraclev10g.body:
DECLARE 
envbq_status number;
valor_envbq_update number;
vro_error  tkr_errores%ROWTYPE;
BEGIN
    -- Caso INSERT
    IF INSERTING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_CONVENIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_CONVENIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_CONVENIOS (
            ENVIO_BQ, ID, ID_ENTIDAD_PADRE, ID_ENTIDAD_HIJO,
            ESTADO, COMIENZA_COBRO, ID_CODIGO_TARIFA_COPAGO, FECHA_CREACION, NOMBRE_CONVENIO
        )
        VALUES (
            0, -- ENVIO_BQ para INSERT
            :NEW.ID, :NEW.ID_ENTIDAD_PADRE, :NEW.ID_ENTIDAD_HIJO,
            :NEW.ESTADO, :NEW.COMIENZA_COBRO, :NEW.ID_CODIGO_TARIFA_COPAGO, :NEW.FECHA_CREACION, :NEW.NOMBRE_CONVENIO
        );
    END IF;

    -- Caso UPDATE
    IF UPDATING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_CONVENIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NULL THEN

            INSERT INTO TKRBQ_CONVENIOS (
                ENVIO_BQ, ID, ID_ENTIDAD_PADRE, ID_ENTIDAD_HIJO,
                ESTADO, COMIENZA_COBRO, ID_CODIGO_TARIFA_COPAGO, FECHA_CREACION, NOMBRE_CONVENIO
            )
            VALUES (
                2, -- ENVIO_BQ para INSERT
                :NEW.ID, :NEW.ID_ENTIDAD_PADRE, :NEW.ID_ENTIDAD_HIJO,
                :NEW.ESTADO, :NEW.COMIENZA_COBRO, :NEW.ID_CODIGO_TARIFA_COPAGO, :NEW.FECHA_CREACION, :NEW.NOMBRE_CONVENIO
            );       

       ELSE
            IF envbq_status = 0 THEN 
                valor_envbq_update := 0;
            ELSE
                valor_envbq_update := 2;
            END IF;    

            UPDATE TKRBQ_CONVENIOS
            SET
                ENVIO_BQ = valor_envbq_update,
                ID = :NEW.ID,
                ID_ENTIDAD_PADRE = :NEW.ID_ENTIDAD_PADRE,
                ID_ENTIDAD_HIJO = :NEW.ID_ENTIDAD_HIJO,
                ESTADO = :NEW.ESTADO,
                COMIENZA_COBRO = :NEW.COMIENZA_COBRO,
                ID_CODIGO_TARIFA_COPAGO = :NEW.ID_CODIGO_TARIFA_COPAGO,
                FECHA_CREACION = :NEW.FECHA_CREACION,
                NOMBRE_CONVENIO = :NEW.NOMBRE_CONVENIO
            WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
        END IF;
    END IF;

    -- Caso DELETE
    IF DELETING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_CONVENIOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_CONVENIOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_CONVENIOS (
            ENVIO_BQ, ID, ID_ENTIDAD_PADRE, ID_ENTIDAD_HIJO,
            ESTADO, COMIENZA_COBRO, ID_CODIGO_TARIFA_COPAGO, FECHA_CREACION, NOMBRE_CONVENIO
        )
        VALUES (
            -1, -- ENVIO_BQ para DELETE
            :OLD.ID, :OLD.ID_ENTIDAD_PADRE, :OLD.ID_ENTIDAD_HIJO,
            :OLD.ESTADO, :OLD.COMIENZA_COBRO, :OLD.ID_CODIGO_TARIFA_COPAGO, :OLD.FECHA_CREACION, :OLD.NOMBRE_CONVENIO
        );
    END IF;

    EXCEPTION
        WHEN OTHERS
        THEN
            vro_error.nombre_programa := 'TRG_SYNC_TKR_CONVENIOS';
            vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ';
            vro_error.parametros := 'id de consultas: '||:old.id;
            uti_ge_excepciones_pkg.p_grabar_log (vro_error);

END;
